def distancen(blobn):
    wincx=160
    wincy=120
    x=blobn.x()
    y=blobn.y()
    return   math.sqrt(math.pow(wincx-x,2)+math.pow(wincy-y,2))
def compareblobs(blob1,blob2):
    temp=distancen(blob1)-distancen(blob2)
    if temp>0:
        return 1
    elif temp<0:
        return -1
    else:
        return 0
