def lcd_show_except(e):
    import uio
    err_str = uio.StringIO()
    sys.print_exception(e, err_str)
    err_str = err_str.getvalue()
    img = image.Image(size=(224,224))
    img.draw_string(0, 10, err_str, scale=1, color=(0xff,0x00,0x00))
    lcd.display(img)

def main(anchors, labels = None, model_addr="/sd/m.kmodel", sensor_window=(224, 224), lcd_rotation=2, sensor_hmirror=True, sensor_vflip=True):
    sensor.reset()
    sensor.set_pixformat(sensor.RGB565)
    sensor.set_framesize(sensor.QVGA)
    sensor.set_windowing(sensor_window)
    sensor.set_hmirror(sensor_hmirror)
    sensor.set_vflip(sensor_vflip)
    sensor.run(1)

    lcd.init(type=1)
    lcd.rotation(lcd_rotation)
    lcd.clear(lcd.WHITE)

    if not labels:
        with open('labels.txt','r') as f:
            exec(f.read())
    if not labels:
        print("no labels.txt")
        img = image.Image(size=(320, 240))
        img.draw_string(90, 110, "no labels.txt", color=(255, 0, 0), scale=2)
        lcd.display(img)
        return 1
    try:
        img = image.Image("startup.jpg")
        lcd.display(img)
    except Exception:
        img = image.Image(size=(320, 240))
        img.draw_string(90, 110, "loading model...", color=(255, 255, 255), scale=2)
        lcd.display(img)

    try:
        task = None
        task = kpu.load(model_addr)
        kpu.init_yolo2(task, 0.5, 0.3, 5, anchors) # threshold:[0,1], nms_value: [0, 1]
        while(True):
            img = sensor.snapshot()
            t = time.ticks_ms()
            nearblob=None

            try:
                objects = kpu.run_yolo2(task, img)
            except Exception as e:
                print(e)
            t = time.ticks_ms() - t
            if objects:
                print(objects)
                nearblob=objects[0]
                for obj in objects:
                    pos = obj.rect()
                    if compareblobs(nearblob,obj)==1:
                        nearblob = obj
                    img.draw_rectangle(pos)
                    img.draw_string(pos[0], pos[1], "%s : %.2f" %(labels[obj.classid()], obj.value()), scale=2, color=(255, 0, 0))



                    nearpos = nearblob.rect()
                    print(nearpos[0]+nearpos[2]/2,nearpos[1]+nearpos[3]/2)
                    a= pixwl_to_realty(nearpos[0]+nearpos[2]/2,(nearpos[1]+nearpos[3]/2))
                    x_a = a[0]-0.03
                    Y_a = a[1]+0.015
                    out_str="HEAD,%f,%f,-0.16,%d,TAIL"%(x_a,Y_a,4)
                    byte_x = pack('f',a[0])
                    byte_y = pack('f',a[1])
                    byte_z = pack('f',-0.07)
               # data = ustruct.pack("bbbbbbbbbbbbbbb",0x24,byte_x[0],byte_x[1],byte_x[2],byte_x[3],byte_y[0],byte_y[1],byte_y[2],byte_y[3],byte_z[0],byte_z[1],byte_z[2],byte_z[3],(nearblob.classid())+1,0x23)
                    print(out_str)
                #print([ i for i in data])
                    uart.write(out_str)
            #time.sleep(1)
            try:
                img.draw_string(0, 200, "t:%dms" %(t), scale=2, color=(255, 0, 0))
                lcd.display(img)
            except Exception as e:
                print(e)

    except Exception as e:
        raise e
    finally:
        print("end");
        if not task is None:
            kpu.deinit(task)
